// On récupère le tableau des tailles depuis le premier (et seul) item entrant
const sizes = $('Summarize').first().json.appended_sizeNumber;

// On utilise la méthode reduce pour additionner toutes les valeurs
const totalSize = sizes.reduce((acc, current) => acc + Number(current), 0);

// On retourne le résultat
return {
  total_size_bytes: totalSize,
  total_size_mb: (totalSize / 1024 / 1024).toFixed(2) // Petit bonus en Mo
};

// La fonction reste la même
function calculerTempsEcoule(startTime, stopTime) {
  const start = new Date(startTime);
  const stop = new Date(stopTime);
  const diffMs = stop - start;
  const secondes = Math.abs(diffMs / 1000);
  return `${secondes} secondes`;
}

// Récupération des données depuis les nœuds précédents
const tempsDepart = $('Get Time Start1').first().json.currentDate;
const tempsStop = $input.first().json.currentDate;

// Calcul
const resultat = calculerTempsEcoule(tempsDepart, tempsStop);

// IMPORTANT : Pour n8n, il faut retourner un tableau d'objets
return [
  {
    json: {
      temps_depart: tempsDepart,
      temps_stop: tempsStop,
      duree_totale: resultat
    }
  }
];
